class Solution:
    def numberOfSubstrings(self, s: str) -> int:
        count = [0, 0, 0]
        required = 3
        formed = 0
        ans = 0
        left = 0
        for right in range(len(s)):
            character = s[right]
            if character == 'a':
                count[0] += 1
            elif character == 'b':
                count[1] += 1
            else:
                count[2] += 1

            if count[0] > 0 and count[1] > 0 and count[2] > 0:
                formed = 3

            while formed == 3:
                character = s[left]
                if character == 'a':
                    count[0] -= 1
                elif character == 'b':
                    count[1] -= 1
                else:
                    count[2] -= 1

                if count[0] == 0 or count[1] == 0 or count[2] == 0:
                    formed -= 1

                ans += len(s) - right

                left += 1

        return ans
